export interface CharacterStyle {
  tone: 'friendly' | 'excited' | 'calm' | 'wise';
  length: 'short' | 'medium';
}

export interface Character {
  id: string;
  name: string;
  persona: string;
  systemPrompt: string;
  voice: 'Zephyr' | 'Puck' | 'Charon' | 'Kore' | 'Fenrir';
  style: CharacterStyle;
  image: string;
  isDefault?: boolean;
}

export interface Settings {
  searchEnabled: boolean;
  safeSearchStrict: boolean;
  timeLimitMinutes: number;
  remainingTime: number;
}

export interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_SAFETY_RULES } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const checkContentSafety = async (text: string): Promise<{ safe: boolean; reason?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Perform an 8-year-old child safety check on the following character description or message. 
      Flag any NSFW, violence, horror, or inappropriate themes. 
      Reply ONLY with a JSON object: {"safe": boolean, "reason": "string|null"}

      Content: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            safe: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["safe"]
        }
      }
    });

    return JSON.parse(response.text || '{"safe": false, "reason": "Parsing error"}');
  } catch (err) {
    console.error("Safety check failed", err);
    return { safe: false, reason: "Service error" };
  }
};

export const getEncyclopediaAnswer = async (query: string, characterPrompt: string, useSearch: boolean) => {
  const tools = useSearch ? [{ googleSearch: {} }] : [];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: `${SYSTEM_SAFETY_RULES}\n${characterPrompt}`,
        tools: tools as any
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (err) {
    console.error("Query failed", err);
    return { text: "Oh oh! I couldn't find that out right now. Let's try something else!", sources: [] };
  }
};

import React, { useState } from 'react';
import { Character } from '../types';
import { checkContentSafety } from '../services/geminiService';

interface Props {
  characters: Character[];
  selectedId: string;
  onSelect: (id: string) => void;
  onAdd: (char: Character) => void;
}

export const CharacterSelector: React.FC<Props> = ({ characters, selectedId, onSelect, onAdd }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newPersona, setNewPersona] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleAdd = async () => {
    if (!newName || !newPersona) return;
    setLoading(true);
    setError('');

    const safety = await checkContentSafety(newPersona);
    if (!safety.safe) {
      setError(`Wait! This character isn't safe for kids: ${safety.reason}`);
      setLoading(false);
      return;
    }

    const newChar: Character = {
      id: Date.now().toString(),
      name: newName,
      persona: newPersona,
      systemPrompt: `You are ${newName}. ${newPersona}`,
      voice: 'Kore',
      style: { tone: 'friendly', length: 'medium' },
      image: `https://picsum.photos/seed/${newName}/400/400`,
    };

    onAdd(newChar);
    setIsAdding(false);
    setNewName('');
    setNewPersona('');
    setLoading(false);
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-sky-800 mb-6 flex items-center gap-2">
        <i className="fas fa-users"></i> Choose Your Friend
      </h2>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-6">
        {characters.map(char => (
          <button
            key={char.id}
            onClick={() => onSelect(char.id)}
            className={`relative group p-4 rounded-3xl transition-all ${
              selectedId === char.id 
                ? 'bg-sky-400 text-white shadow-lg ring-4 ring-sky-200 scale-105' 
                : 'bg-white hover:bg-sky-50 shadow-md border-2 border-transparent'
            }`}
          >
            <img 
              src={char.image} 
              alt={char.name}
              className="w-full aspect-square rounded-2xl object-cover mb-3"
            />
            <p className="font-semibold text-center truncate">{char.name}</p>
            {selectedId === char.id && (
              <div className="absolute -top-2 -right-2 bg-yellow-400 w-8 h-8 rounded-full flex items-center justify-center text-white border-2 border-white">
                <i className="fas fa-check"></i>
              </div>
            )}
          </button>
        ))}

        <button
          onClick={() => setIsAdding(true)}
          className="p-4 rounded-3xl bg-white border-2 border-dashed border-sky-300 hover:border-sky-500 hover:bg-sky-50 transition-colors flex flex-col items-center justify-center text-sky-500 gap-2"
        >
          <div className="w-12 h-12 rounded-full bg-sky-100 flex items-center justify-center">
            <i className="fas fa-plus text-xl"></i>
          </div>
          <p className="font-medium">New Friend</p>
        </button>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl p-8 max-w-md w-full shadow-2xl">
            <h3 className="text-xl font-bold text-sky-800 mb-4">Create a Friend</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">Name</label>
                <input 
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none"
                  placeholder="e.g. Sunny the Bee"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">Who are they?</label>
                <textarea 
                  value={newPersona}
                  onChange={(e) => setNewPersona(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none min-h-[100px]"
                  placeholder="e.g. A tiny honeybee that loves to teach about flowers and gardening..."
                />
              </div>
              {error && <p className="text-red-500 text-sm bg-red-50 p-3 rounded-lg border border-red-200">{error}</p>}
              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setIsAdding(false)}
                  className="flex-1 py-3 rounded-2xl bg-gray-100 text-gray-600 font-bold hover:bg-gray-200 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleAdd}
                  disabled={loading || !newName || !newPersona}
                  className="flex-1 py-3 rounded-2xl bg-sky-500 text-white font-bold hover:bg-sky-600 transition-colors disabled:opacity-50"
                >
                  {loading ? <i className="fas fa-spinner fa-spin mr-2"></i> : 'Create!'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

