import React, { useState, useEffect, useRef } from 'react';
import { Character, Message, Settings } from '../types';
import { getEncyclopediaAnswer } from '../services/geminiService';

interface Props {
  character: Character;
  settings: Settings;
}

export const MagicChat: React.FC<Props> = ({ character, settings }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async (text?: string) => {
    const content = text || inputValue;
    if (!content.trim()) return;

    const userMsg: Message = { role: 'user', content, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    const response = await getEncyclopediaAnswer(
      content, 
      character.systemPrompt, 
      settings.searchEnabled
    );

    const aiMsg: Message = { role: 'assistant', content: response.text || '', timestamp: Date.now() };
    setMessages(prev => [...prev, aiMsg]);
    setIsTyping(false);

    // In a real app, we would trigger the TTS engine here
    console.log("Playing voice:", character.voice, response.text);
  };

  const simulateVoiceInput = () => {
    setIsListening(true);
    // Simulate speech recognition
    setTimeout(() => {
      setIsListening(false);
      handleSend("Why is the sky blue?");
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-4xl mx-auto">
      {/* Top Bar / Character Info */}
      <div className="flex items-center gap-4 bg-white/80 backdrop-blur p-4 rounded-3xl shadow-sm mb-4">
        <img src={character.image} className="w-14 h-14 rounded-full ring-2 ring-sky-300" />
        <div>
          <h3 className="font-bold text-sky-900">{character.name}</h3>
          <p className="text-xs text-sky-600 font-medium">Chatting with you!</p>
        </div>
        <div className="ml-auto flex items-center gap-2 px-4 py-2 bg-sky-100 rounded-full">
           <i className="fas fa-clock text-sky-500"></i>
           <span className="font-bold text-sky-700">{settings.remainingTime}m</span>
        </div>
      </div>

      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 px-2 pb-6 scrollbar-hide"
      >
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
             <div className="w-32 h-32 bg-sky-100 rounded-full flex items-center justify-center bubble-anim">
                <i className="fas fa-magic text-5xl text-sky-400"></i>
             </div>
             <div>
                <h2 className="text-xl font-bold text-sky-800">Hi there!</h2>
                <p className="text-sky-600">I'm {character.name}. You can ask me anything about animals, space, or science!</p>
             </div>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-sky-500 text-white rounded-br-none' 
                : 'bg-white text-gray-800 rounded-bl-none border-b-2 border-gray-100'
            }`}>
              {msg.content}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex gap-1">
              <span className="w-2 h-2 bg-sky-200 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-sky-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-2 h-2 bg-sky-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
            </div>
          </div>
        )}
      </div>

      {/* Input Bar */}
      <div className="relative pt-4">
        {isListening && (
          <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-sky-500 text-white px-6 py-2 rounded-full shadow-lg animate-pulse">
            Listening... 👂
          </div>
        )}

        <div className="bg-white rounded-full shadow-xl p-2 flex items-center gap-2 ring-4 ring-sky-50">
          <button 
            onClick={simulateVoiceInput}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
              isListening ? 'bg-red-500 animate-pulse' : 'bg-sky-500 hover:bg-sky-600'
            } text-white shadow-lg`}
          >
            <i className={`fas ${isListening ? 'fa-microphone' : 'fa-microphone-lines'} text-xl`}></i>
          </button>

          <input 
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Type your question..."
            className="flex-1 bg-transparent border-none outline-none px-4 font-medium text-lg placeholder:text-gray-300"
          />

          <button 
            onClick={() => handleSend()}
            disabled={!inputValue.trim()}
            className="w-12 h-12 bg-sky-100 text-sky-600 rounded-full hover:bg-sky-200 transition-colors disabled:opacity-50"
          >
            <i className="fas fa-paper-plane"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Character, Settings } from './types';
import { DEFAULT_CHARACTERS } from './constants';
import { CharacterSelector } from './components/CharacterSelector';
import { ParentalPortal } from './components/ParentalPortal';
import { MagicChat } from './components/MagicChat';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'chat' | 'characters' | 'parents'>('chat');
  const [characters, setCharacters] = useState<Character[]>(DEFAULT_CHARACTERS);
  const [selectedCharId, setSelectedCharId] = useState(DEFAULT_CHARACTERS[0].id);
  const [settings, setSettings] = useState<Settings>({
    searchEnabled: true,
    safeSearchStrict: true,
    timeLimitMinutes: 60,
    remainingTime: 60
  });

  const selectedChar = characters.find(c => c.id === selectedCharId) || characters[0];

  // Timer logic for remaining time
  useEffect(() => {
    const timer = setInterval(() => {
      setSettings(prev => ({
        ...prev,
        remainingTime: Math.max(0, prev.remainingTime - 1)
      }));
    }, 60000); // Reduce 1 minute every 60 seconds

    return () => clearInterval(timer);
  }, []);

  const handleAddCharacter = (char: Character) => {
    setCharacters(prev => [...prev, char]);
    setSelectedCharId(char.id);
    setActiveTab('chat');
  };

  return (
    <div className="min-h-screen flex flex-col max-w-6xl mx-auto shadow-2xl bg-sky-50/50">
      {/* App Header */}
      <header className="p-4 bg-white border-b border-sky-100 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-yellow-400 rounded-2xl flex items-center justify-center shadow-md rotate-3">
            <i className="fas fa-book-open text-white text-2xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-black text-sky-900 leading-none">Magic</h1>
            <p className="text-xs font-bold text-sky-500 uppercase tracking-widest">Encyclopedia</p>
          </div>
        </div>

        <nav className="flex bg-sky-50 p-1.5 rounded-2xl gap-1">
          <button 
            onClick={() => setActiveTab('chat')}
            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${
              activeTab === 'chat' ? 'bg-white text-sky-600 shadow-sm' : 'text-sky-400 hover:text-sky-600'
            }`}
          >
            <i className="fas fa-message mr-2"></i> Chat
          </button>
          <button 
            onClick={() => setActiveTab('characters')}
            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${
              activeTab === 'characters' ? 'bg-white text-sky-600 shadow-sm' : 'text-sky-400 hover:text-sky-600'
            }`}
          >
            <i className="fas fa-paw mr-2"></i> Friends
          </button>
          <button 
            onClick={() => setActiveTab('parents')}
            className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${
              activeTab === 'parents' ? 'bg-white text-sky-600 shadow-sm' : 'text-sky-400 hover:text-sky-600'
            }`}
          >
            <i className="fas fa-shield-halved mr-2"></i> Parents
          </button>
        </nav>
      </header>

      {/* Main Viewport */}
      <main className="flex-1 overflow-hidden relative">
        <div className={`h-full transition-all duration-300 ${activeTab === 'chat' ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full absolute inset-0'}`}>
          <div className="p-4 h-full">
            <MagicChat character={selectedChar} settings={settings} />
          </div>
        </div>

        <div className={`h-full transition-all duration-300 ${activeTab === 'characters' ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-full absolute inset-0'}`}>
          <div className="h-full overflow-y-auto">
            <CharacterSelector 
              characters={characters} 
              selectedId={selectedCharId} 
              onSelect={setSelectedCharId} 
              onAdd={handleAddCharacter}
            />
          </div>
        </div>

        <div className={`h-full transition-all duration-300 ${activeTab === 'parents' ? 'opacity-100 scale-100' : 'opacity-0 scale-95 absolute inset-0 pointer-events-none'}`}>
          <div className="h-full overflow-y-auto">
            <ParentalPortal settings={settings} onUpdate={setSettings} />
          </div>
        </div>
      </main>

      {/* Decorative footer */}
      <footer className="h-1 bg-gradient-to-r from-sky-400 via-yellow-400 to-green-400"></footer>
    </div>
  );
};

export default App;

