export function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function encodeBase64(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SYSTEM_SAFETY_RULES } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const checkContentSafety = async (text: string): Promise<{ safe: boolean; reason?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Perform an 8-year-old child safety check on the following character description or message. 
      Flag any NSFW, violence, horror, or inappropriate themes. 
      Reply ONLY with a JSON object: {"safe": boolean, "reason": "string|null"}

      Content: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            safe: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["safe"]
        }
      }
    });

    return JSON.parse(response.text || '{"safe": false, "reason": "Parsing error"}');
  } catch (err) {
    console.error("Safety check failed", err);
    return { safe: false, reason: "Service error" };
  }
};

export const getEncyclopediaAnswer = async (query: string, characterPrompt: string, useSearch: boolean) => {
  const tools = useSearch ? [{ googleSearch: {} }] : [];

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: query,
      config: {
        systemInstruction: `${SYSTEM_SAFETY_RULES}\n${characterPrompt}`,
        tools: tools as any
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (err) {
    console.error("Query failed", err);
    return { text: "Oh oh! I couldn't find that out right now. Let's try something else!", sources: [] };
  }
};

export const generateTTS = async (text: string, voiceName: string): Promise<string | undefined> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say this clearly for a child: ${text}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceName as any },
          },
        },
      },
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (err) {
    console.error("TTS generation failed", err);
    return undefined;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Character, Message, Settings } from '../types';
import { getEncyclopediaAnswer, generateTTS } from '../services/geminiService';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';

interface Props {
  character: Character;
  settings: Settings;
}

export const MagicChat: React.FC<Props> = ({ character, settings }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const stopCurrentAudio = () => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
      } catch (e) {
        // Source might have already ended
      }
      currentSourceRef.current = null;
    }
    setIsSpeaking(false);
  };

  const playTTS = async (text: string) => {
    stopCurrentAudio();

    const base64Audio = await generateTTS(text, character.voice);
    if (!base64Audio) return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    try {
      const audioBuffer = await decodeAudioData(
        decodeBase64(base64Audio),
        ctx,
        24000,
        1
      );

      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);

      source.onended = () => {
        setIsSpeaking(false);
        currentSourceRef.current = null;
      };

      currentSourceRef.current = source;
      setIsSpeaking(true);
      source.start();
    } catch (err) {
      console.error("Audio playback error", err);
      setIsSpeaking(false);
    }
  };

  const handleSend = async (text?: string) => {
    const content = text || inputValue;
    if (!content.trim()) return;

    // Stop any current speaking when new interaction starts
    stopCurrentAudio();

    const userMsg: Message = { role: 'user', content, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    const response = await getEncyclopediaAnswer(
      content, 
      character.systemPrompt, 
      settings.searchEnabled
    );

    const responseText = response.text || "I'm sorry, I couldn't find an answer to that.";
    const aiMsg: Message = { role: 'assistant', content: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, aiMsg]);
    setIsTyping(false);

    // Auto-play response
    playTTS(responseText);
  };

  const simulateVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    // Simulate speech recognition
    setTimeout(() => {
      setIsListening(false);
      handleSend("Why is the sky blue?");
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-4xl mx-auto">
      {/* Top Bar / Character Info */}
      <div className="flex items-center gap-4 bg-white/80 backdrop-blur p-4 rounded-3xl shadow-sm mb-4">
        <div className="relative">
          <img src={character.image} className="w-14 h-14 rounded-full ring-2 ring-sky-300" />
          {isSpeaking && (
            <div className="absolute -bottom-1 -right-1 bg-green-500 w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
              <span className="flex gap-0.5">
                <span className="w-1 h-2 bg-white rounded-full animate-pulse"></span>
                <span className="w-1 h-3 bg-white rounded-full animate-pulse [animation-delay:0.2s]"></span>
                <span className="w-1 h-2 bg-white rounded-full animate-pulse [animation-delay:0.4s]"></span>
              </span>
            </div>
          )}
        </div>
        <div>
          <h3 className="font-bold text-sky-900">{character.name}</h3>
          <p className="text-xs text-sky-600 font-medium">{isSpeaking ? 'Speaking...' : 'Ready to help!'}</p>
        </div>
        <div className="ml-auto flex items-center gap-2">
          {isSpeaking && (
            <button 
              onClick={stopCurrentAudio}
              className="p-2 text-red-400 hover:text-red-600 transition-colors"
              title="Stop speaking"
            >
              <i className="fas fa-volume-xmark"></i>
            </button>
          )}
          <div className="flex items-center gap-2 px-4 py-2 bg-sky-100 rounded-full">
            <i className="fas fa-clock text-sky-500"></i>
            <span className="font-bold text-sky-700">{settings.remainingTime}m</span>
          </div>
        </div>
      </div>

      {/* Chat Area */}
      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 px-2 pb-6 scrollbar-hide"
      >
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
             <div className="w-32 h-32 bg-sky-100 rounded-full flex items-center justify-center bubble-anim">
                <i className="fas fa-magic text-5xl text-sky-400"></i>
             </div>
             <div>
                <h2 className="text-xl font-bold text-sky-800">Hi there!</h2>
                <p className="text-sky-600">I'm {character.name}. You can ask me anything about animals, space, or science!</p>
             </div>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`group relative max-w-[85%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-sky-500 text-white rounded-br-none' 
                : 'bg-white text-gray-800 rounded-bl-none border-b-2 border-gray-100'
            }`}>
              {msg.content}
              {msg.role === 'assistant' && (
                <button 
                  onClick={() => playTTS(msg.content)}
                  className="absolute -right-8 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-sky-400 hover:text-sky-600"
                >
                  <i className="fas fa-volume-up"></i>
                </button>
              )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex gap-1">
              <span className="w-2 h-2 bg-sky-200 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-sky-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-2 h-2 bg-sky-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
            </div>
          </div>
        )}
      </div>

      {/* Input Bar */}
      <div className="relative pt-4">
        {isListening && (
          <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-sky-500 text-white px-6 py-2 rounded-full shadow-lg animate-pulse">
            Listening... 👂
          </div>
        )}

        <div className="bg-white rounded-full shadow-xl p-2 flex items-center gap-2 ring-4 ring-sky-50">
          <button 
            onClick={simulateVoiceInput}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
              isListening ? 'bg-red-500 animate-pulse' : 'bg-sky-500 hover:bg-sky-600'
