              <span className="font-bold text-amber-600 min-w-[80px] text-right">{settings.timeLimitMinutes} mins</span>
            </div>
          </div>

          <div className="p-4 border-2 border-amber-100 rounded-2xl bg-amber-50/30">
            <h3 className="font-bold text-amber-800 mb-2 flex items-center gap-2">
              <i className="fas fa-info-circle"></i> Usage Summary
            </h3>
            <p className="text-amber-700 text-sm">
              Total time used today: <span className="font-bold">{settings.timeLimitMinutes - settings.remainingTime} mins</span>
            </p>
          </div>
        </section>

        {/* Conversation History Section */}
        <section className="space-y-4 pt-8 border-t border-gray-100">
          <div className="flex justify-between items-center">
            <h3 className="text-xl font-bold text-gray-800 flex items-center gap-2">
              <i className="fas fa-history text-sky-500"></i> Conversation Records
