        <div className="pt-4 text-center">
          <p className="text-xs text-gray-400 uppercase tracking-wider font-bold">Safe Search Mode: ALWAYS ON</p>
        </div>
      </div>
    </div>
  );
};

export interface CharacterStyle {
  tone: 'friendly' | 'excited' | 'calm' | 'wise';
  length: 'short' | 'medium';
}

export type GeminiVoice = 'Zephyr' | 'Puck' | 'Charon' | 'Kore' | 'Fenrir';

export interface Character {
  id: string;
  name: string;
  persona: string;
  systemPrompt: string;
  voice: GeminiVoice;
  style: CharacterStyle;
  image: string;
  isDefault?: boolean;
}

export interface Settings {
  searchEnabled: boolean;
  safeSearchStrict: boolean;
  timeLimitMinutes: number;
  remainingTime: number;
}

export interface Message {
  role: 'user' | 'assistant';
  content: string;
