import React, { useState, useRef } from 'react';
import { Character, GeminiVoice } from '../types';
import { checkContentSafety, generateTTS } from '../services/geminiService';
import { AVAILABLE_VOICES } from '../constants';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';

interface Props {
  characters: Character[];
  selectedId: string;
  onSelect: (id: string) => void;
  onAdd: (char: Character) => void;
}

export const CharacterSelector: React.FC<Props> = ({ characters, selectedId, onSelect, onAdd }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newPersona, setNewPersona] = useState('');
  const [newVoice, setNewVoice] = useState<GeminiVoice>('Zephyr');
  const [loading, setLoading] = useState(false);
  const [previewing, setPreviewing] = useState(false);
  const [error, setError] = useState('');

  const audioContextRef = useRef<AudioContext | null>(null);

  const handlePreviewVoice = async () => {
    if (previewing) return;
    setPreviewing(true);

    try {
      const text = `Hi! I'm your new friend, ${newName || 'a mystery pal'}. I can't wait to play!`;
      const base64Audio = await generateTTS(text, newVoice);
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const ctx = audioContextRef.current;
        const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(ctx.destination);
        source.start();
        source.onended = () => setPreviewing(false);
      } else {
        setPreviewing(false);
      }
    } catch (err) {
      console.error("Voice preview failed", err);
      setPreviewing(false);
    }
  };

  const handleAdd = async () => {
    if (!newName || !newPersona) return;
    setLoading(true);
    setError('');

    const safety = await checkContentSafety(newPersona);
    if (!safety.safe) {
      setError(`Wait! This character isn't safe for kids: ${safety.reason}`);
      setLoading(false);
      return;
    }

    const newChar: Character = {
      id: Date.now().toString(),
      name: newName,
      persona: newPersona,
      systemPrompt: `You are ${newName}. ${newPersona}`,
      voice: newVoice,
      style: { tone: 'friendly', length: 'medium' },
      image: `https://picsum.photos/seed/${newName}/400/400`,
    };

    onAdd(newChar);
    setIsAdding(false);
    setNewName('');
    setNewPersona('');
    setNewVoice('Zephyr');
    setLoading(false);
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-sky-800 mb-6 flex items-center gap-2">
        <i className="fas fa-users"></i> Choose Your Friend
      </h2>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-6">
        {characters.map(char => (
          <button
            key={char.id}
            onClick={() => onSelect(char.id)}
            className={`relative group p-4 rounded-3xl transition-all ${
              selectedId === char.id 
                ? 'bg-sky-400 text-white shadow-lg ring-4 ring-sky-200 scale-105' 
                : 'bg-white hover:bg-sky-50 shadow-md border-2 border-transparent'
            }`}
          >
            <img 
              src={char.image} 
              alt={char.name}
              className="w-full aspect-square rounded-2xl object-cover mb-3"
            />
            <p className="font-semibold text-center truncate">{char.name}</p>
            <div className="text-[10px] bg-sky-100 text-sky-600 rounded-full px-2 py-0.5 mt-1 mx-auto w-fit font-bold uppercase">
              {char.voice}
            </div>
            {selectedId === char.id && (
              <div className="absolute -top-2 -right-2 bg-yellow-400 w-8 h-8 rounded-full flex items-center justify-center text-white border-2 border-white">
                <i className="fas fa-check"></i>
              </div>
            )}
          </button>
        ))}

        <button
          onClick={() => setIsAdding(true)}
          className="p-4 rounded-3xl bg-white border-2 border-dashed border-sky-300 hover:border-sky-500 hover:bg-sky-50 transition-colors flex flex-col items-center justify-center text-sky-500 gap-2"
        >
          <div className="w-12 h-12 rounded-full bg-sky-100 flex items-center justify-center">
            <i className="fas fa-plus text-xl"></i>
          </div>
          <p className="font-medium">New Friend</p>
        </button>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl p-8 max-w-md w-full shadow-2xl overflow-y-auto max-h-[90vh]">
            <h3 className="text-xl font-bold text-sky-800 mb-4">Create a Friend</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">Name</label>
                <input 
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none"
                  placeholder="e.g. Sunny the Bee"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">Who are they?</label>
                <textarea 
                  value={newPersona}
                  onChange={(e) => setNewPersona(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none min-h-[80px]"
                  placeholder="e.g. A tiny honeybee that loves flowers..."
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">Pick a Voice</label>
                <div className="flex gap-2">
                  <select 
                    value={newVoice}
                    onChange={(e) => setNewVoice(e.target.value as GeminiVoice)}
                    className="flex-1 px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none bg-white font-medium text-sky-700"
                  >
                    {AVAILABLE_VOICES.map(v => (
                      <option key={v.name} value={v.name}>{v.name} ({v.description})</option>
                    ))}
                  </select>
                  <button 
                    onClick={handlePreviewVoice}
                    disabled={previewing}
                    className={`w-12 h-10 rounded-xl flex items-center justify-center transition-all ${
                      previewing ? 'bg-sky-100 text-sky-300' : 'bg-sky-500 text-white hover:bg-sky-600'
                    }`}
                    title="Preview Voice"
                  >
                    <i className={`fas ${previewing ? 'fa-spinner fa-spin' : 'fa-volume-up'}`}></i>
                  </button>
                </div>
              </div>
              {error && <p className="text-red-500 text-sm bg-red-50 p-3 rounded-lg border border-red-200">{error}</p>}
              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setIsAdding(false)}
                  className="flex-1 py-3 rounded-2xl bg-gray-100 text-gray-600 font-bold hover:bg-gray-200 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleAdd}
                  disabled={loading || !newName || !newPersona}
                  className="flex-1 py-3 rounded-2xl bg-sky-500 text-white font-bold hover:bg-sky-600 transition-colors disabled:opacity-50"
                >
                  {loading ? <i className="fas fa-spinner fa-spin mr-2"></i> : 'Create!'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Character, GeminiVoice } from '../types';
import { checkContentSafety, generateTTS } from '../services/geminiService';
import { AVAILABLE_VOICES } from '../constants';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';

interface Props {
  characters: Character[];
  selectedId: string;
  onSelect: (id: string) => void;
  onAdd: (char: Character) => void;
