export const CharacterSelector: React.FC<Props> = ({ characters, selectedId, onSelect, onAdd }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newPersona, setNewPersona] = useState('');
