import React, { useState, useEffect, useRef } from 'react';
import { Character, Message, Settings } from '../types';
import { getEncyclopediaAnswer, generateTTS } from '../services/geminiService';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';
import { UI_TRANSLATIONS } from '../locales';

interface Props {
  character: Character;
  settings: Settings;
  history: Message[];
  onAddMessage: (msg: Message) => void;
}

export const MagicChat: React.FC<Props> = ({ character, settings, history, onAddMessage }) => {
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const t = UI_TRANSLATIONS[settings.language];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isTyping]);

  const stopCurrentAudio = () => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
      } catch (e) {}
      currentSourceRef.current = null;
    }
    setIsSpeaking(false);
  };

  const playTTS = async (text: string) => {
    stopCurrentAudio();
    const base64Audio = await generateTTS(text, character.voice, settings.language);
    if (!base64Audio) return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    try {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => {
        setIsSpeaking(false);
        currentSourceRef.current = null;
      };
      currentSourceRef.current = source;
      setIsSpeaking(true);
      source.start();
    } catch (err) {
      console.error("Audio playback error", err);
      setIsSpeaking(false);
    }
  };

  const handleSend = async (text?: string) => {
    const content = text || inputValue;
    if (!content.trim()) return;

    stopCurrentAudio();

    const userMsg: Message = { 
      role: 'user', 
      content, 
      timestamp: Date.now(),
      characterId: character.id 
    };
    onAddMessage(userMsg);
    setInputValue('');
    setIsTyping(true);

    const response = await getEncyclopediaAnswer(
      content, 
      character.systemPrompt, 
      settings.searchEnabled,
      settings.language
    );

    const responseText = response.text || "I'm sorry, I couldn't find an answer to that.";
    const aiMsg: Message = { 
      role: 'assistant', 
      content: responseText, 
      timestamp: Date.now(),
      characterId: character.id
    };
    onAddMessage(aiMsg);
    setIsTyping(false);

    playTTS(responseText);
  };

  const simulateVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    // Simple logic for default query based on language
    const defaultQueries: any = {
      en: "Why is the sky blue?",
      de: "Warum ist der Himmel blau?",
      zh: "天空为什么是蓝色的？",
      ja: "空はなぜ青いの？",
      fr: "Pourquoi le ciel est-il bleu ?",
      es: "¿Por qué el cielo es azul?",
      it: "Perché il cielo è blu?"
    };
    setTimeout(() => {
      setIsListening(false);
      handleSend(defaultQueries[settings.language] || "Hello!");
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-4xl mx-auto">
      <div className="flex items-center gap-4 bg-white/80 backdrop-blur p-4 rounded-3xl shadow-sm mb-4 border border-sky-100">
        <div className="relative">
          <img src={character.image} className="w-14 h-14 rounded-full ring-2 ring-sky-300" />
          {isSpeaking && (
            <div className="absolute -bottom-1 -right-1 bg-green-500 w-5 h-5 rounded-full flex items-center justify-center border-2 border-white">
              <span className="flex gap-0.5">
                <span className="w-1 h-2 bg-white rounded-full animate-pulse"></span>
                <span className="w-1 h-3 bg-white rounded-full animate-pulse [animation-delay:0.2s]"></span>
                <span className="w-1 h-2 bg-white rounded-full animate-pulse [animation-delay:0.4s]"></span>
              </span>
            </div>
          )}
        </div>
        <div>
          <h3 className="font-bold text-sky-900">{character.name}</h3>
          <p className="text-xs text-sky-600 font-medium">{isSpeaking ? t.speaking : t.ready}</p>
        </div>
        <div className="ml-auto flex items-center gap-2">
          {isSpeaking && (
            <button 
              onClick={stopCurrentAudio}
              className="p-2 text-red-400 hover:text-red-600 transition-colors"
              title="Stop"
            >
              <i className="fas fa-volume-xmark"></i>
            </button>
          )}
          <div className="flex items-center gap-2 px-4 py-2 bg-sky-100 rounded-full">
            <i className="fas fa-clock text-sky-500"></i>
            <span className="font-bold text-sky-700">{settings.remainingTime}{t.mins}</span>
          </div>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 px-2 pb-6 scrollbar-hide"
      >
        {history.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
             <div className="w-32 h-32 bg-sky-100 rounded-full flex items-center justify-center bubble-anim">
                <i className="fas fa-magic text-5xl text-sky-400"></i>
             </div>
             <div>
                <h2 className="text-xl font-bold text-sky-800">{t.hi}</h2>
                <p className="text-sky-600">{t.intro(character.name)}</p>
             </div>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`group relative max-w-[85%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? 'bg-sky-500 text-white rounded-br-none' 
                : 'bg-white text-gray-800 rounded-bl-none border-b-2 border-gray-100'
            }`}>
              {msg.content}
              {msg.role === 'assistant' && (
                <button 
                  onClick={() => playTTS(msg.content)}
                  className="absolute -right-8 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-sky-400 hover:text-sky-600"
                >
                  <i className="fas fa-volume-up"></i>
                </button>
              )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex gap-1">
              <span className="w-2 h-2 bg-sky-200 rounded-full animate-bounce"></span>
              <span className="w-2 h-2 bg-sky-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
              <span className="w-2 h-2 bg-sky-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
            </div>
          </div>
        )}
      </div>

      <div className="relative pt-4">
        {isListening && (
          <div className="absolute -top-12 left-1/2 -translate-x-1/2 bg-sky-500 text-white px-6 py-2 rounded-full shadow-lg animate-pulse">
            Listening... 👂
          </div>
        )}

        <div className="bg-white rounded-full shadow-xl p-2 flex items-center gap-2 ring-4 ring-sky-50">
          <button 
            onClick={simulateVoiceInput}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
              isListening ? 'bg-red-500 animate-pulse' : 'bg-sky-500 hover:bg-sky-600'
            } text-white shadow-lg`}
          >
            <i className={`fas ${isListening ? 'fa-microphone' : 'fa-microphone-lines'} text-xl`}></i>
          </button>

          <input 
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={t.typePlaceholder}
            className="flex-1 bg-transparent border-none outline-none px-4 font-medium text-lg placeholder:text-gray-300"
          />

          <button 
            onClick={() => handleSend()}
            disabled={!inputValue.trim() || isTyping}
            className="w-12 h-12 bg-sky-100 text-sky-600 rounded-full hover:bg-sky-200 transition-colors disabled:opacity-50"
          >
            {isTyping ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Character, GeminiVoice, AppLanguage } from '../types';
import { checkContentSafety, generateTTS } from '../services/geminiService';
import { AVAILABLE_VOICES } from '../constants';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';
import { UI_TRANSLATIONS } from '../locales';

interface Props {
  characters: Character[];
  selectedId: string;
  onSelect: (id: string) => void;
  onAdd: (char: Character) => void;
  lang: AppLanguage;
}

export const CharacterSelector: React.FC<Props> = ({ characters, selectedId, onSelect, onAdd, lang }) => {
  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newPersona, setNewPersona] = useState('');
  const [newSystemPrompt, setNewSystemPrompt] = useState('');
  const [newVoice, setNewVoice] = useState<GeminiVoice>('Zephyr');
  const [loading, setLoading] = useState(false);
  const [previewing, setPreviewing] = useState(false);
  const [error, setError] = useState('');
  const [showAdvanced, setShowAdvanced] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const t = UI_TRANSLATIONS[lang];

  // Automatically update the system prompt recommendation as they type persona
  useEffect(() => {
    if (!showAdvanced && newPersona && newName) {
      setNewSystemPrompt(`You are ${newName}, a friendly companion for an 8-year-old child. ${newPersona}. Always be kind, helpful, and use simple language.`);
    }
  }, [newName, newPersona, showAdvanced]);

  const handlePreviewVoice = async () => {
    if (previewing) return;
    setPreviewing(true);

    try {
      const text = t.intro(newName || 'Friend');
      const base64Audio = await generateTTS(text, newVoice, lang);
      if (base64Audio) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        }
        const ctx = audioContextRef.current;
        const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
        const source = ctx.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(ctx.destination);
        source.start();
        source.onended = () => setPreviewing(false);
      } else {
        setPreviewing(false);
      }
    } catch (err) {
      console.error("Voice preview failed", err);
      setPreviewing(false);
    }
  };

  const handleAdd = async () => {
    if (!newName || !newPersona) return;
    setLoading(true);
    setError('');

    const contentToWash = `${newPersona} ${newSystemPrompt}`;
    const safety = await checkContentSafety(contentToWash);
    if (!safety.safe) {
      setError(`Safety check failed: ${safety.reason}`);
      setLoading(false);
      return;
    }

    const newChar: Character = {
      id: Date.now().toString(),
      name: newName,
      persona: newPersona,
      systemPrompt: newSystemPrompt || `You are ${newName}. ${newPersona}`,
      voice: newVoice,
      style: { tone: 'friendly', length: 'medium' },
      image: `https://picsum.photos/seed/${newName}/400/400`,
    };

    onAdd(newChar);
    setIsAdding(false);
    setNewName('');
    setNewPersona('');
    setNewSystemPrompt('');
    setNewVoice('Zephyr');
    setShowAdvanced(false);
    setLoading(false);
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h2 className="text-2xl font-bold text-sky-800 mb-6 flex items-center gap-2">
        <i className="fas fa-users"></i> {t.chooseFriend}
      </h2>

      <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-6">
        {characters.map(char => (
          <button
            key={char.id}
            onClick={() => onSelect(char.id)}
            className={`relative group p-4 rounded-3xl transition-all ${
              selectedId === char.id 
                ? 'bg-sky-400 text-white shadow-lg ring-4 ring-sky-200 scale-105' 
                : 'bg-white hover:bg-sky-50 shadow-md border-2 border-transparent'
            }`}
          >
            <img 
              src={char.image} 
              alt={char.name}
              className="w-full aspect-square rounded-2xl object-cover mb-3"
            />
            <p className="font-semibold text-center truncate">{char.name}</p>
            <div className="text-[10px] bg-sky-100 text-sky-600 rounded-full px-2 py-0.5 mt-1 mx-auto w-fit font-bold uppercase">
              {char.voice}
            </div>
            {selectedId === char.id && (
              <div className="absolute -top-2 -right-2 bg-yellow-400 w-8 h-8 rounded-full flex items-center justify-center text-white border-2 border-white">
                <i className="fas fa-check"></i>
              </div>
            )}
          </button>
        ))}

        <button
          onClick={() => setIsAdding(true)}
          className="p-4 rounded-3xl bg-white border-2 border-dashed border-sky-300 hover:border-sky-500 hover:bg-sky-50 transition-colors flex flex-col items-center justify-center text-sky-500 gap-2 min-h-[180px]"
        >
          <div className="w-12 h-12 rounded-full bg-sky-100 flex items-center justify-center">
            <i className="fas fa-plus text-xl"></i>
          </div>
          <p className="font-medium">{t.newFriend}</p>
        </button>
      </div>

      {isAdding && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-3xl p-8 max-w-md w-full shadow-2xl overflow-y-auto max-h-[90vh]">
            <h3 className="text-xl font-bold text-sky-800 mb-4">{t.createFriend}</h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">{t.name}</label>
                <input 
                  type="text"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">{t.whoAreThey}</label>
                <textarea 
                  value={newPersona}
                  onChange={(e) => setNewPersona(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none min-h-[80px]"
                />
              </div>

              <div className="pt-2">
                <button 
                  type="button"
                  onClick={() => setShowAdvanced(!showAdvanced)}
                  className="text-xs font-bold text-sky-500 hover:text-sky-700 flex items-center gap-1 uppercase tracking-wider"
                >
                  {showAdvanced ? <i className="fas fa-chevron-up"></i> : <i className="fas fa-chevron-down"></i>}
                  Advanced
                </button>

                {showAdvanced && (
                  <div className="mt-3 bg-sky-50 p-4 rounded-2xl border border-sky-100">
                    <label className="block text-xs font-bold text-sky-700 mb-2 uppercase">Custom Prompt</label>
                    <textarea 
                      value={newSystemPrompt}
                      onChange={(e) => setNewSystemPrompt(e.target.value)}
                      className="w-full px-3 py-2 rounded-xl border border-sky-200 focus:border-sky-400 outline-none min-h-[100px] text-sm bg-white"
                    />
                  </div>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-600 mb-1">{t.pickVoice}</label>
                <div className="flex gap-2">
                  <select 
                    value={newVoice}
                    onChange={(e) => setNewVoice(e.target.value as GeminiVoice)}
                    className="flex-1 px-4 py-2 rounded-xl border-2 border-sky-100 focus:border-sky-400 outline-none bg-white font-medium text-sky-700"
                  >
                    {AVAILABLE_VOICES.map(v => (
                      <option key={v.name} value={v.name}>{v.name} ({v.description})</option>
                    ))}
                  </select>
                  <button 
                    onClick={handlePreviewVoice}
                    disabled={previewing}
                    className={`w-12 h-10 rounded-xl flex items-center justify-center transition-all ${
                      previewing ? 'bg-sky-100 text-sky-300' : 'bg-sky-500 text-white hover:bg-sky-600'
                    }`}
                  >
                    <i className={`fas ${previewing ? 'fa-spinner fa-spin' : 'fa-volume-up'}`}></i>
                  </button>
                </div>
              </div>
              {error && <p className="text-red-500 text-sm bg-red-50 p-3 rounded-lg border border-red-200">{error}</p>}
              <div className="flex gap-3 pt-4">
                <button 
                  onClick={() => setIsAdding(false)}
                  className="flex-1 py-3 rounded-2xl bg-gray-100 text-gray-600 font-bold hover:bg-gray-200 transition-colors"
                >
                  {t.cancel}
                </button>
                <button 
                  onClick={handleAdd}
                  disabled={loading || !newName || !newPersona}
                  className="flex-1 py-3 rounded-2xl bg-sky-500 text-white font-bold hover:bg-sky-600 transition-colors disabled:opacity-50"
                >
                  {loading ? <i className="fas fa-spinner fa-spin mr-2"></i> : t.create}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
