}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SYSTEM_SAFETY_RULES } from "../constants";
import { AppLanguage, AppTheme } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const getLanguageName = (lang: AppLanguage) => {
  const names: Record<AppLanguage, string> = {
    en: 'English',
    de: 'German',
    zh: 'Chinese',
    ja: 'Japanese',
    fr: 'French',
    es: 'Spanish',
    it: 'Italian'
  };
  return names[lang];
};

export const checkContentSafety = async (text: string): Promise<{ safe: boolean; reason?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Perform an 8-year-old child safety check on the following character description or message. 
      Flag any NSFW, violence, horror, or inappropriate themes. 
      Reply ONLY with a JSON object: {"safe": boolean, "reason": "string|null"}

      Content: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            safe: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["safe"]
        }
      }
    });

    return JSON.parse(response.text || '{"safe": false, "reason": "Parsing error"}');
  } catch (err) {
    console.error("Safety check failed", err);
    return { safe: false, reason: "Service error" };
  }
};

/**
 * Generates an image based on a text prompt.
 * Uses the gemini-2.5-flash-image model.
 */
export const generateImage = async (prompt: string): Promise<string | undefined> => {
  const modelToUse = 'gemini-2.5-flash-image'; 

  try {
    const response = await ai.models.generateContent({
      model: modelToUse,
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1", // Default to square images for consistency
        },
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData && part.inlineData.mimeType.startsWith('image/')) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return undefined;
  } catch (err) {
    console.error("Image generation failed", err);
    return undefined;
  }
};


export const getEncyclopediaAnswer = async (query: string, characterPrompt: string, useSearch: boolean, lang: AppLanguage, theme: AppTheme) => {
  const tools = useSearch ? [{ googleSearch: {} }] : [];
  const languageContext = `IMPORTANT: You must respond in ${getLanguageName(lang)}. You are speaking to an 8-year-old child.`;

  const isImageRequest = (q: string) => {
    const lowerQuery = q.toLowerCase();
    return lowerQuery.includes('show me a picture of') ||
           lowerQuery.includes('show a picture of') ||
           lowerQuery.includes('draw a picture of') ||
           lowerQuery.includes('can you draw') ||
           lowerQuery.includes('image of') ||
           lowerQuery.includes('picture of');
  };

  let assistantText = '';
  let generatedImageUrl: string | undefined;
  let sources: any[] = [];

  if (isImageRequest(query)) {
    // Extract the part of the query that describes the image
    const imagePromptMatch = query.match(/(?:show me a picture of|show a picture of|draw a picture of|can you draw|image of|picture of)\s*(.*)/i);
    const imagePrompt = imagePromptMatch && imagePromptMatch[1] ? imagePromptMatch[1].trim() : query.replace(/show me a|show a|draw a|can you|image|picture/i, '').trim();

    if (imagePrompt) {
      assistantText = `Okay! Here is an image of "${imagePrompt}"!`;
      generatedImageUrl = await generateImage(imagePrompt);
      if (!generatedImageUrl) {
        assistantText = `I tried to create an image of "${imagePrompt}", but something went wrong. Could you try a different request?`;
      }
    } else {
      assistantText = "I can show you a picture! What would you like it to be of?";
    }
  } else {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: query,
        config: {
          systemInstruction: `${SYSTEM_SAFETY_RULES}\n${languageContext}\n${characterPrompt}`,
          tools: tools as any
        }
      });
      assistantText = response.text || "Oh oh! I couldn't find that out right now.";
      sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    } catch (err) {
      console.error("Text generation failed", err);
      assistantText = "Oh oh! I couldn't find that out right now.";
    }
  }

  return {
    text: assistantText,
    imageUrl: generatedImageUrl,
    sources: sources
  };
};

/**
 * Generates speech using the Gemini TTS model.
 * It uses a system instruction to ensure the speech is natural for the target language 
 * and maintains a child-friendly persona.
 */
export const generateTTS = async (text: string, voiceName: string, lang: AppLanguage = 'en'): Promise<string | undefined> => {
  const langName = getLanguageName(lang);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        // We use system instruction to guide the TTS model's performance beyond just the text.
        systemInstruction: `You are a high-quality multilingual speech engine for children. 
        Please read the text provided in ${langName}. 
        The audience is an 8-year-old child, so speak clearly, warmly, and naturally.
        Respect the linguistic nuances of ${langName} while keeping the character's energy level consistent with the chosen voice: ${voiceName}.`,
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            // These voices (Zephyr, Puck, etc.) are cross-lingual and will adapt to the language specified in the prompt/instruction.
            prebuiltVoiceConfig: { voiceName: voiceName as any },
          },
        },
      },
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (err) {
    console.error("TTS generation failed", err);
    return undefined;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Character, Message, Settings } from '../types';
import { getEncyclopediaAnswer, generateTTS } from '../services/geminiService';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';
import { UI_TRANSLATIONS } from '../locales';
import { THEME_CONFIG } from '../constants';

interface Props {
  character: Character;
  settings: Settings;
  history: Message[];
  onAddMessage: (msg: Message) => void;
}

export const MagicChat: React.FC<Props> = ({ character, settings, history, onAddMessage }) => {
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false); // New state for image generation
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const t = UI_TRANSLATIONS[settings.language];
  const theme = THEME_CONFIG[settings.theme];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isTyping, isGeneratingImage]); // Add isGeneratingImage to trigger scroll on image completion

  const stopCurrentAudio = () => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
      } catch (e) {}
      currentSourceRef.current = null;
    }
    setIsSpeaking(false);
  };

  const playTTS = async (text: string) => {
    stopCurrentAudio();
    const base64Audio = await generateTTS(text, character.voice, settings.language);
    if (!base64Audio) return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    try {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => {
        setIsSpeaking(false);
        currentSourceRef.current = null;
      };
      currentSourceRef.current = source;
      setIsSpeaking(true);
      source.start();
    } catch (err) {
      console.error("Audio playback error", err);
      setIsSpeaking(false);
    }
  };

  const handleSend = async (text?: string) => {
    const content = text || inputValue;
    if (!content.trim()) return;

    stopCurrentAudio();

    const userMsg: Message = { 
      role: 'user', 
      content, 
      timestamp: Date.now(),
      characterId: character.id 
    };
    onAddMessage(userMsg);
    setInputValue('');
    setIsTyping(true);
    setIsGeneratingImage(false); // Reset image generation state

    const imageRequestKeywords = ['show me a picture of', 'draw a picture of', 'image of', 'picture of'];
    const isExplicitImageRequest = imageRequestKeywords.some(keyword => content.toLowerCase().includes(keyword));

    if (isExplicitImageRequest) {
      setIsGeneratingImage(true); // Set loading for image generation
    }

    const response = await getEncyclopediaAnswer(
      content, 
      character.systemPrompt, 
      settings.searchEnabled,
      settings.language,
      settings.theme // Pass theme to potentially influence image generation later
    );

    const responseText = response.text || "I'm sorry, I couldn't find an answer to that.";
    const aiMsg: Message = { 
      role: 'assistant', 
      content: responseText, 
      timestamp: Date.now(),
      characterId: character.id,
      imageUrl: response.imageUrl // Include imageUrl if present
    };
    onAddMessage(aiMsg);
    setIsTyping(false);
    setIsGeneratingImage(false); // Clear loading for image generation

    playTTS(responseText);
  };

  const simulateVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    const defaultQueries: any = {
      en: "Why is the sky blue?",
      de: "Warum ist der Himmel blau?",
      zh: "天空为什么是蓝色的？",
      ja: "空はなぜ青いの？",
      fr: "Pourquoi le ciel est-il bleu ?",
      es: "¿Por qué el cielo es azul?",
      it: "Perché il cielo è blu?"
    };
    setTimeout(() => {
      setIsListening(false);
      handleSend(defaultQueries[settings.language] || "Hello!");
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-4xl mx-auto">
      <div className={`flex items-center gap-4 bg-white/80 backdrop-blur p-4 rounded-3xl shadow-sm mb-4 border border-${theme.secondary}`}>
        <div className="relative">
          <img src={character.image} className={`w-14 h-14 rounded-full ring-2 ring-${theme.primary}`} />
          {isSpeaking && (
            <div className={`absolute -bottom-1 -right-1 bg-green-500 w-5 h-5 rounded-full flex items-center justify-center border-2 border-white`}>
              <span className="flex gap-0.5">
                <span className="w-1 h-2 bg-white rounded-full animate-pulse"></span>
                <span className="w-1 h-3 bg-white rounded-full animate-pulse [animation-delay:0.2s]"></span>
                <span className="w-1 h-2 bg-white rounded-full animate-pulse [animation-delay:0.4s]"></span>
              </span>
            </div>
          )}
        </div>
        <div>
          <h3 className={`font-bold text-${theme.text}`}>{character.name}</h3>
          <p className={`text-xs text-${theme.primary} font-medium`}>{isSpeaking ? t.speaking : t.ready}</p>
        </div>
        <div className="ml-auto flex items-center gap-2">
          {isSpeaking && (
            <button 
              onClick={stopCurrentAudio}
              className="p-2 text-red-400 hover:text-red-600 transition-colors"
              title="Stop"
            >
              <i className="fas fa-volume-xmark"></i>
            </button>
          )}
          <div className={`flex items-center gap-2 px-4 py-2 bg-${theme.secondary} rounded-full`}>
            <i className={`fas fa-clock text-${theme.primary} opacity-60`}></i>
            <span className={`font-bold text-${theme.primary}`}>{settings.remainingTime}{t.mins}</span>
          </div>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 px-2 pb-6 scrollbar-hide"
      >
        {history.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
             <div className={`w-32 h-32 bg-${theme.secondary} rounded-full flex items-center justify-center bubble-anim`}>
                <i className={`fas fa-magic text-5xl text-${theme.primary} opacity-40`}></i>
             </div>
             <div>
                <h2 className={`text-xl font-bold text-${theme.text}`}>{t.hi}</h2>
                <p className={`text-${theme.primary}`}>{t.intro(character.name)}</p>
             </div>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`group relative max-w-[85%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? `bg-${theme.primary} text-white rounded-br-none` 
                : 'bg-white text-gray-800 rounded-bl-none border-b-2 border-gray-100'
            }`}>
              {msg.content}
              {msg.imageUrl && (
                <div className="mt-3 rounded-xl overflow-hidden shadow-md border border-gray-100">
                  <img src={msg.imageUrl} alt="Generated content" className="w-full h-auto object-cover" />
                </div>
              )}
              {msg.role === 'assistant' && (
                <button 
                  onClick={() => playTTS(msg.content)}
                  className={`absolute -right-8 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-${theme.primary} hover:opacity-100`}
                >
                  <i className="fas fa-volume-up"></i>
                </button>
              )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex gap-1">
              <span className={`w-2 h-2 bg-${theme.primary} opacity-20 rounded-full animate-bounce`}></span>
              <span className={`w-2 h-2 bg-${theme.primary} opacity-40 rounded-full animate-bounce [animation-delay:0.2s]`}></span>
              <span className={`w-2 h-2 bg-${theme.primary} opacity-60 rounded-full animate-bounce [animation-delay:0.4s]`}></span>
            </div>
          </div>
        )}

        {isGeneratingImage && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex items-center gap-3">
              <div className={`w-6 h-6 border-2 border-dashed border-${theme.primary} rounded-full animate-spin`}></div>
              <span className="text-gray-600">Generating image...</span>
            </div>
          </div>
        )}
      </div>

      <div className="relative pt-4">
        {isListening && (
          <div className={`absolute -top-12 left-1/2 -translate-x-1/2 bg-${theme.primary} text-white px-6 py-2 rounded-full shadow-lg animate-pulse`}>
            Listening... 👂
          </div>
        )}

        <div className={`bg-white rounded-full shadow-xl p-2 flex items-center gap-2 ring-4 ring-${theme.secondary}`}>
          <button 
            onClick={simulateVoiceInput}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
              isListening ? 'bg-red-500 animate-pulse' : `bg-${theme.primary} hover:opacity-90`
            } text-white shadow-lg`}
          >
            <i className={`fas ${isListening ? 'fa-microphone' : 'fa-microphone-lines'} text-xl`}></i>
          </button>

          <input 
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={t.typePlaceholder}
            className={`flex-1 bg-transparent border-none outline-none px-4 font-medium text-lg placeholder:text-gray-300 text-${theme.text}`}
          />

          <button 
            onClick={() => handleSend()}
            disabled={!inputValue.trim() || isTyping || isGeneratingImage}
            className={`w-12 h-12 bg-${theme.secondary} text-${theme.primary} rounded-full hover:bg-opacity-80 transition-colors disabled:opacity-50`}
          >
            {isTyping || isGeneratingImage ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Character, Settings, Message, AppLanguage, AppTheme } from './types';
import { DEFAULT_CHARACTERS, THEME_CONFIG } from './constants';
import { CharacterSelector } from './components/CharacterSelector';
import { ParentalPortal } from './components/ParentalPortal';
import { MagicChat } from './components/MagicChat';
import { UI_TRANSLATIONS, LANGUAGE_LABELS } from './locales';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'chat' | 'characters' | 'parents'>('chat');
  const [characters, setCharacters] = useState<Character[]>(() => {
    const saved = localStorage.getItem('magic_encyclopedia_characters');
    if (saved) return JSON.parse(saved);
    return DEFAULT_CHARACTERS;
  });
  const [selectedCharId, setSelectedCharId] = useState(() => {
    const saved = localStorage.getItem('magic_encyclopedia_selected_char');
    return saved || DEFAULT_CHARACTERS[0].id;
  });

  const [settings, setSettings] = useState<Settings>(() => {
    const saved = localStorage.getItem('magic_encyclopedia_settings');
    if (saved) return JSON.parse(saved);
    return {
      searchEnabled: true,
      safeSearchStrict: true,
      timeLimitMinutes: 60,
      remainingTime: 60,
      language: 'en',
      theme: 'neutral'
    };
  });

  const [history, setHistory] = useState<Message[]>(() => {
    const saved = localStorage.getItem('magic_encyclopedia_history');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('magic_encyclopedia_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('magic_encyclopedia_settings', JSON.stringify(settings));
  }, [settings]);

  useEffect(() => {
    localStorage.setItem('magic_encyclopedia_characters', JSON.stringify(characters));
  }, [characters]);

  useEffect(() => {
    localStorage.setItem('magic_encyclopedia_selected_char', selectedCharId);
  }, [selectedCharId]);

  const selectedChar = characters.find(c => c.id === selectedCharId) || characters[0];
  const t = UI_TRANSLATIONS[settings.language];
  const theme = THEME_CONFIG[settings.theme];

  useEffect(() => {
    const timer = setInterval(() => {
      setSettings(prev => ({
        ...prev,
        remainingTime: Math.max(0, prev.remainingTime - 1)
      }));
    }, 60000);
    return () => clearInterval(timer);
  }, []);

  const handleAddCharacter = (char: Character) => {
    setCharacters(prev => [...prev, char]);
    setSelectedCharId(char.id);
    setActiveTab('chat');
  };

  const handleUpdateCharacter = (updatedChar: Character) => {
    setCharacters(prev => prev.map(c => c.id === updatedChar.id ? updatedChar : c));
  };

  const handleDeleteCharacter = (id: string) => {
    if (characters.length <= 1) return;
    setCharacters(prev => prev.filter(c => c.id !== id));
    if (selectedCharId === id) {
      setSelectedCharId(characters.find(c => c.id !== id)?.id || '');
    }
  };

  const handleAddMessage = (msg: Message) => {
    setHistory(prev => [...prev, msg]);
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('magic_encyclopedia_history');
  };

  return (
    <div className={`min-h-screen flex flex-col max-w-6xl mx-auto shadow-2xl transition-colors duration-500 bg-${theme.bg}`}>
      <header className={`p-4 bg-${theme.header} border-b border-${theme.secondary} flex items-center justify-between shadow-sm`}>
        <div className="flex items-center gap-3">
          <div className={`w-12 h-12 bg-${theme.accent} rounded-2xl flex items-center justify-center shadow-md rotate-3`}>
            <i className={`fas fa-book-open text-white text-2xl`}></i>
          </div>
          <div className="hidden sm:block">
            <h1 className={`text-xl font-black text-${theme.text} leading-none`}>Magic</h1>
            <p className={`text-xs font-bold text-${theme.primary} uppercase tracking-widest`}>Encyclopedia</p>
          </div>
        </div>

        <nav className={`flex bg-${theme.secondary} p-1.5 rounded-2xl gap-1`}>
          <button 
            onClick={() => setActiveTab('chat')}
            className={`px-3 sm:px-5 py-2.5 rounded-xl text-xs sm:text-sm font-bold transition-all ${
              activeTab === 'chat' ? `bg-white text-${theme.primary} shadow-sm` : `text-${theme.primary} opacity-60 hover:opacity-100`
            }`}
          >
            <i className="fas fa-message sm:mr-2"></i> <span className="hidden sm:inline">{t.chat}</span>
          </button>
          <button 
            onClick={() => setActiveTab('characters')}
            className={`px-3 sm:px-5 py-2.5 rounded-xl text-xs sm:text-sm font-bold transition-all ${
              activeTab === 'characters' ? `bg-white text-${theme.primary} shadow-sm` : `text-${theme.primary} opacity-60 hover:opacity-100`
            }`}
          >
            <i className="fas fa-paw sm:mr-2"></i> <span className="hidden sm:inline">{t.friends}</span>
          </button>
          <button 
            onClick={() => setActiveTab('parents')}
            className={`px-3 sm:px-5 py-2.5 rounded-xl text-xs sm:text-sm font-bold transition-all ${
              activeTab === 'parents' ? `bg-white text-${theme.primary} shadow-sm` : `text-${theme.primary} opacity-60 hover:opacity-100`
            }`}
          >
            <i className="fas fa-shield-halved sm:mr-2"></i> <span className="hidden sm:inline">{t.parents}</span>
          </button>
        </nav>

        <div className="flex items-center gap-2">
           <div className={`bg-${theme.secondary} px-3 py-1.5 rounded-full flex items-center gap-2 text-${theme.primary} font-bold text-xs`}>
              <i className="fas fa-globe"></i>
              {LANGUAGE_LABELS[settings.language]}
           </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden relative">
        <div className={`h-full transition-all duration-300 ${activeTab === 'chat' ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full absolute inset-0'}`}>
          <div className="p-4 h-full">
            <MagicChat 
              character={selectedChar} 
              settings={settings} 
              history={history.filter(m => m.characterId === selectedCharId)}
              onAddMessage={handleAddMessage}
            />
          </div>
        </div>

        <div className={`h-full transition-all duration-300 ${activeTab === 'characters' ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-full absolute inset-0'}`}>
          <div className="h-full overflow-y-auto">
            <CharacterSelector 
              characters={characters} 
              selectedId={selectedCharId} 
              onSelect={setSelectedCharId} 
              onAdd={handleAddCharacter}
              onUpdate={handleUpdateCharacter}
              onDelete={handleDeleteCharacter}
              lang={settings.language}
              theme={settings.theme}
            />
          </div>
        </div>

        <div className={`h-full transition-all duration-300 ${activeTab === 'parents' ? 'opacity-100 scale-100' : 'opacity-0 scale-95 absolute inset-0 pointer-events-none'}`}>
          <div className="h-full overflow-y-auto">
            <ParentalPortal 
              settings={settings} 
              onUpdate={setSettings} 
              history={history}
              characters={characters}
              onClearHistory={clearHistory}
              lang={settings.language}
            />
          </div>
        </div>
      </main>

      <footer className={`h-1 bg-gradient-to-r from-${theme.primary} via-${theme.accent} to-green-400`}></footer>
    </div>
  );
};

export default App;

export interface CharacterStyle {
  tone: 'friendly' | 'excited' | 'calm' | 'wise';
  length: 'short' | 'medium';
}

export type GeminiVoice = 'Zephyr' | 'Puck' | 'Charon' | 'Kore' | 'Fenrir';
export type AppLanguage = 'en' | 'de' | 'zh' | 'ja' | 'fr' | 'es' | 'it';
export type AppTheme = 'neutral' | 'boy' | 'girl';
export type ApiProvider = 'google' | 'custom';

export interface Character {
  id: string;
  name: string;
  persona: string;
  systemPrompt: string;
  voice: GeminiVoice;
  customVoiceId?: string;
  voiceCloningData?: string;
  style: CharacterStyle;
  image: string;
  isDefault?: boolean;
}

export interface Settings {
  searchEnabled: boolean;
  safeSearchStrict: boolean;
  timeLimitMinutes: number;
  remainingTime: number;
  language: AppLanguage;
  theme: AppTheme;
  apiProvider: ApiProvider;
  customApiUrl?: string;
  customApiKey?: string;
  customModelName?: string;
}

export interface Message {
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
  characterId: string;
  imageUrl?: string;
}

import { GoogleGenAI, Type, Modality } from "@google/genai";
import { SYSTEM_SAFETY_RULES } from "../constants";
import { AppLanguage, AppTheme, Settings } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const getLanguageName = (lang: AppLanguage) => {
  const names: Record<AppLanguage, string> = {
    en: 'English',
    de: 'German',
    zh: 'Chinese',
    ja: 'Japanese',
    fr: 'French',
    es: 'Spanish',
    it: 'Italian'
  };
  return names[lang];
};

export const checkContentSafety = async (text: string): Promise<{ safe: boolean; reason?: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Perform an 8-year-old child safety check on the following character description or message. 
      Flag any NSFW, violence, horror, or inappropriate themes. 
      Reply ONLY with a JSON object: {"safe": boolean, "reason": "string|null"}

      Content: "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            safe: { type: Type.BOOLEAN },
            reason: { type: Type.STRING }
          },
          required: ["safe"]
        }
      }
    });

    return JSON.parse(response.text || '{"safe": false, "reason": "Parsing error"}');
  } catch (err) {
    console.error("Safety check failed", err);
    return { safe: false, reason: "Service error" };
  }
};

export const generateImage = async (prompt: string): Promise<string | undefined> => {
  const modelToUse = 'gemini-2.5-flash-image'; 

  try {
    const response = await ai.models.generateContent({
      model: modelToUse,
      contents: {
        parts: [
          { text: prompt },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
        },
      },
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData && part.inlineData.mimeType.startsWith('image/')) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return undefined;
  } catch (err) {
    console.error("Image generation failed", err);
    return undefined;
  }
};

const callCustomApi = async (query: string, systemPrompt: string, settings: Settings) => {
  if (!settings.customApiUrl || !settings.customApiKey) {
    throw new Error("Custom API settings incomplete");
  }

  const response = await fetch(`${settings.customApiUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${settings.customApiKey}`
    },
    body: JSON.stringify({
      model: settings.customModelName || 'gpt-3.5-turbo',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: query }
      ],
      temperature: 0.7
    })
  });

  if (!response.ok) {
    const err = await response.text();
    throw new Error(`Custom API error: ${err}`);
  }

  const data = await response.json();
  return data.choices[0].message.content;
};

export const getEncyclopediaAnswer = async (query: string, characterPrompt: string, settings: Settings) => {
  const lang = settings.language;
  const useSearch = settings.searchEnabled;
  const languageContext = `IMPORTANT: You must respond in ${getLanguageName(lang)}. You are speaking to an 8-year-old child.`;
  const fullSystemPrompt = `${SYSTEM_SAFETY_RULES}\n${languageContext}\n${characterPrompt}`;

  const isImageRequest = (q: string) => {
    const lowerQuery = q.toLowerCase();
    const keywords = ['show me a picture of', 'show a picture of', 'draw a picture of', 'can you draw', 'image of', 'picture of'];
    return keywords.some(k => lowerQuery.includes(k));
  };

  let assistantText = '';
  let generatedImageUrl: string | undefined;
  let sources: any[] = [];

  if (isImageRequest(query)) {
    const imagePromptMatch = query.match(/(?:show me a picture of|show a picture of|draw a picture of|can you draw|image of|picture of)\s*(.*)/i);
    const imagePrompt = imagePromptMatch && imagePromptMatch[1] ? imagePromptMatch[1].trim() : query.replace(/show me a|show a|draw a|can you|image|picture/i, '').trim();

    if (imagePrompt) {
      assistantText = `Okay! Here is an image of "${imagePrompt}"!`;
      generatedImageUrl = await generateImage(imagePrompt);
      if (!generatedImageUrl) {
        assistantText = `I tried to create an image of "${imagePrompt}", but something went wrong. Could you try a different request?`;
      }
    } else {
      assistantText = "I can show you a picture! What would you like it to be of?";
    }
  } else {
    try {
      if (settings.apiProvider === 'custom') {
        assistantText = await callCustomApi(query, fullSystemPrompt, settings);
      } else {
        const tools = useSearch ? [{ googleSearch: {} }] : [];
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: query,
          config: {
            systemInstruction: fullSystemPrompt,
            tools: tools as any
          }
        });
        assistantText = response.text || "Oh oh! I couldn't find that out right now.";
        sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      }
    } catch (err) {
      console.error("Text generation failed", err);
      assistantText = "Oh oh! My magic brain is a bit tired. Can you ask again in a moment?";
    }
  }

  return {
    text: assistantText,
    imageUrl: generatedImageUrl,
    sources: sources
  };
};

export const generateTTS = async (text: string, voiceName: string, lang: AppLanguage = 'en'): Promise<string | undefined> => {
  const langName = getLanguageName(lang);

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        systemInstruction: `You are a high-quality multilingual speech engine for children. 
        Please read the text provided in ${langName}. 
        The audience is an 8-year-old child, so speak clearly, warmly, and naturally.
        Respect the linguistic nuances of ${langName} while keeping the character's energy level consistent with the chosen voice: ${voiceName}.`,
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: voiceName as any },
          },
        },
      },
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (err) {
    console.error("TTS generation failed", err);
    return undefined;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Character, Message, Settings } from '../types';
import { getEncyclopediaAnswer, generateTTS } from '../services/geminiService';
import { decodeBase64, decodeAudioData } from '../services/audioUtils';
import { UI_TRANSLATIONS } from '../locales';
import { THEME_CONFIG } from '../constants';

interface Props {
  character: Character;
  settings: Settings;
  history: Message[];
  onAddMessage: (msg: Message) => void;
}

export const MagicChat: React.FC<Props> = ({ character, settings, history, onAddMessage }) => {
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);

  const t = UI_TRANSLATIONS[settings.language];
  const theme = THEME_CONFIG[settings.theme];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [history, isTyping, isGeneratingImage]);

  const stopCurrentAudio = () => {
    if (currentSourceRef.current) {
      try {
        currentSourceRef.current.stop();
      } catch (e) {}
      currentSourceRef.current = null;
    }
    setIsSpeaking(false);
  };

  const playTTS = async (text: string) => {
    stopCurrentAudio();
    const base64Audio = await generateTTS(text, character.voice, settings.language);
    if (!base64Audio) return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;

    try {
      const audioBuffer = await decodeAudioData(decodeBase64(base64Audio), ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(ctx.destination);
      source.onended = () => {
        setIsSpeaking(false);
        currentSourceRef.current = null;
      };
      currentSourceRef.current = source;
      setIsSpeaking(true);
      source.start();
    } catch (err) {
      console.error("Audio playback error", err);
      setIsSpeaking(false);
    }
  };

  const handleSend = async (text?: string) => {
    const content = text || inputValue;
    if (!content.trim()) return;

    stopCurrentAudio();

    const userMsg: Message = { 
      role: 'user', 
      content, 
      timestamp: Date.now(),
      characterId: character.id 
    };
    onAddMessage(userMsg);
    setInputValue('');
    setIsTyping(true);
    setIsGeneratingImage(false);

    const imageRequestKeywords = ['show me a picture of', 'draw a picture of', 'image of', 'picture of'];
    const isExplicitImageRequest = imageRequestKeywords.some(keyword => content.toLowerCase().includes(keyword));

    if (isExplicitImageRequest) {
      setIsGeneratingImage(true);
    }

    const response = await getEncyclopediaAnswer(
      content, 
      character.systemPrompt, 
      settings
    );

    const responseText = response.text || "I'm sorry, I couldn't find an answer to that.";
    const aiMsg: Message = { 
      role: 'assistant', 
      content: responseText, 
      timestamp: Date.now(),
      characterId: character.id,
      imageUrl: response.imageUrl
    };
    onAddMessage(aiMsg);
    setIsTyping(false);
    setIsGeneratingImage(false);

    playTTS(responseText);
  };

  const simulateVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    const defaultQueries: any = {
      en: "Why is the sky blue?",
      de: "Warum ist der Himmel blau?",
      zh: "天空为什么是蓝色的？",
      ja: "空はなぜ青いの？",
      fr: "Pourquoi le ciel est-il bleu ?",
      es: "¿Por qué el cielo es azul?",
      it: "Perché il cielo è blu?"
    };
    setTimeout(() => {
      setIsListening(false);
      handleSend(defaultQueries[settings.language] || "Hello!");
    }, 2000);
  };

  return (
    <div className="flex flex-col h-[calc(100vh-160px)] max-w-4xl mx-auto">
      <div className={`flex items-center gap-4 bg-white/80 backdrop-blur p-4 rounded-3xl shadow-sm mb-4 border border-${theme.secondary}`}>
        <div className="relative">
          <img src={character.image} className={`w-14 h-14 rounded-full ring-2 ring-${theme.primary}`} />
          {isSpeaking && (
            <div className={`absolute -bottom-1 -right-1 bg-green-500 w-5 h-5 rounded-full flex items-center justify-center border-2 border-white`}>
              <span className="flex gap-0.5">
                <span className="w-1 h-2 bg-white rounded-full animate-pulse"></span>
                <span className="w-1 h-3 bg-white rounded-full animate-pulse [animation-delay:0.2s]"></span>
                <span className="w-1 h-2 bg-white rounded-full animate-pulse [animation-delay:0.4s]"></span>
              </span>
            </div>
          )}
        </div>
        <div>
          <h3 className={`font-bold text-${theme.text}`}>{character.name}</h3>
          <p className={`text-xs text-${theme.primary} font-medium`}>{isSpeaking ? t.speaking : t.ready}</p>
        </div>
        <div className="ml-auto flex items-center gap-2">
          {isSpeaking && (
            <button 
              onClick={stopCurrentAudio}
              className="p-2 text-red-400 hover:text-red-600 transition-colors"
              title="Stop"
            >
              <i className="fas fa-volume-xmark"></i>
            </button>
          )}
          <div className={`flex items-center gap-2 px-4 py-2 bg-${theme.secondary} rounded-full`}>
            <i className={`fas fa-clock text-${theme.primary} opacity-60`}></i>
            <span className={`font-bold text-${theme.primary}`}>{settings.remainingTime}{t.mins}</span>
          </div>
        </div>
      </div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto space-y-4 px-2 pb-6 scrollbar-hide"
      >
        {history.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
             <div className={`w-32 h-32 bg-${theme.secondary} rounded-full flex items-center justify-center bubble-anim`}>
                <i className={`fas fa-magic text-5xl text-${theme.primary} opacity-40`}></i>
             </div>
             <div>
                <h2 className={`text-xl font-bold text-${theme.text}`}>{t.hi}</h2>
                <p className={`text-${theme.primary}`}>{t.intro(character.name)}</p>
             </div>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`group relative max-w-[85%] p-4 rounded-2xl shadow-sm ${
              msg.role === 'user' 
                ? `bg-${theme.primary} text-white rounded-br-none` 
                : 'bg-white text-gray-800 rounded-bl-none border-b-2 border-gray-100'
            }`}>
              {msg.content}
              {msg.imageUrl && (
                <div className="mt-3 rounded-xl overflow-hidden shadow-md border border-gray-100">
                  <img src={msg.imageUrl} alt="Generated content" className="w-full h-auto object-cover" />
                </div>
              )}
              {msg.role === 'assistant' && (
                <button 
                  onClick={() => playTTS(msg.content)}
                  className={`absolute -right-8 top-1/2 -translate-y-1/2 opacity-0 group-hover:opacity-100 transition-opacity p-2 text-${theme.primary} hover:opacity-100`}
                >
                  <i className="fas fa-volume-up"></i>
                </button>
              )}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex gap-1">
              <span className={`w-2 h-2 bg-${theme.primary} opacity-20 rounded-full animate-bounce`}></span>
              <span className={`w-2 h-2 bg-${theme.primary} opacity-40 rounded-full animate-bounce [animation-delay:0.2s]`}></span>
              <span className={`w-2 h-2 bg-${theme.primary} opacity-60 rounded-full animate-bounce [animation-delay:0.4s]`}></span>
            </div>
          </div>
        )}

        {isGeneratingImage && (
          <div className="flex justify-start">
            <div className="bg-white p-4 rounded-2xl shadow-sm border-b-2 border-gray-100 flex items-center gap-3">
              <div className={`w-6 h-6 border-2 border-dashed border-${theme.primary} rounded-full animate-spin`}></div>
              <span className="text-gray-600">Generating image...</span>
            </div>
          </div>
        )}
      </div>

      <div className="relative pt-4">
        {isListening && (
          <div className={`absolute -top-12 left-1/2 -translate-x-1/2 bg-${theme.primary} text-white px-6 py-2 rounded-full shadow-lg animate-pulse`}>
            Listening... 👂
          </div>
        )}

        <div className={`bg-white rounded-full shadow-xl p-2 flex items-center gap-2 ring-4 ring-${theme.secondary}`}>
          <button 
            onClick={simulateVoiceInput}
            className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
              isListening ? 'bg-red-500 animate-pulse' : `bg-${theme.primary} hover:opacity-90`
            } text-white shadow-lg`}
          >
            <i className={`fas ${isListening ? 'fa-microphone' : 'fa-microphone-lines'} text-xl`}></i>
          </button>

          <input 
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={t.typePlaceholder}
            className={`flex-1 bg-transparent border-none outline-none px-4 font-medium text-lg placeholder:text-gray-300 text-${theme.text}`}
          />

          <button 
            onClick={() => handleSend()}
            disabled={!inputValue.trim() || isTyping || isGeneratingImage}
            className={`w-12 h-12 bg-${theme.secondary} text-${theme.primary} rounded-full hover:bg-opacity-80 transition-colors disabled:opacity-50`}
          >
            {isTyping || isGeneratingImage ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-paper-plane"></i>}
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
