                    <span className="text-gray-400 font-medium">
                      {new Date(msg.timestamp).toLocaleString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                  </div>
                  <p className={`text-sm text-${theme.text} leading-relaxed font-medium opacity-90`}>{msg.content}</p>
                </div>
