          <div className={`flex-1 h-full transition-all duration-300 ${activeTab === 'characters' ? 'opacity-100 z-10' : 'opacity-0 z-0 absolute inset-0 pointer-events-none translate-y-4'}`}>
            <div className="h-full overflow-y-auto scrollbar-hide">
              <CharacterSelector 
                characters={characters} 
                selectedId={selectedCharId} 
                onSelect={setSelectedCharId} 
                onAdd={handleAddCharacter}
                onUpdate={handleUpdateCharacter}
                onDelete={handleDeleteCharacter}
                lang={settings.language}
                theme={settings.theme}
                settings={settings}
              />
            </div>
          </div>

          <div className={`flex-1 h-full transition-all duration-300 ${activeTab === 'parents' ? 'opacity-100 z-10 scale-100' : 'opacity-0 z-0 absolute inset-0 pointer-events-none scale-95 translate-y-4'}`}>
            <div className="h-full overflow-y-auto scrollbar-hide">
              <ParentalPortal 
                settings={settings} 
                onUpdate={setSettings} 
                history={history}
                characters={characters}
                onClearHistory={clearHistory}
                lang={settings.language}
              />
