            className={`w-10 h-10 sm:w-12 sm:h-12 flex-shrink-0 bg-${theme.secondary} text-${theme.primary} rounded-full hover:bg-opacity-80 transition-colors disabled:opacity-50 flex items-center justify-center`}
          >
